"""Baseline rate statistics for resurgence detection (pure functions, no I/O)."""

from __future__ import annotations

import math
from dataclasses import dataclass
from datetime import datetime


@dataclass(frozen=True)
class BaselineStats:
    sample_count: int
    window_minutes: int
    mean_per_minute: float
    stddev_per_minute: float
    spike_threshold: float


def compute_baseline_stats(
    per_minute_counts: list[tuple[datetime, int]],
    window_start: datetime,
    window_end: datetime,
) -> BaselineStats:
    total_window_minutes = int((window_end - window_start).total_seconds() / 60)
    if total_window_minutes <= 0:
        return BaselineStats(0, 0, 0.0, 0.0, float("inf"))

    counts = [0] * total_window_minutes
    for minute_start, count in per_minute_counts:
        offset = int((minute_start - window_start).total_seconds() / 60)
        if 0 <= offset < total_window_minutes:
            counts[offset] = count

    sample_count = sum(counts)
    if sample_count == 0:
        return BaselineStats(0, total_window_minutes, 0.0, 0.0, float("inf"))

    mean = sample_count / total_window_minutes
    variance = sum((c - mean) ** 2 for c in counts) / total_window_minutes
    stddev = math.sqrt(variance)
    spike_threshold = mean + 2 * stddev
    return BaselineStats(
        sample_count, total_window_minutes, mean, stddev, spike_threshold
    )


def is_spike(
    current_rate_per_minute: float, stats: BaselineStats, min_sample_count: int
) -> bool:
    if stats.sample_count < min_sample_count:
        return False
    return current_rate_per_minute > stats.spike_threshold

